const allItems = $input.all();

const cashflowData = allItems.filter(i => i.json.sheet === 'CashFlow' || i.json.cash_in !== undefined);
const revenueData = allItems.filter(i => i.json.sheet === 'Revenue' || i.json.revenue_current !== undefined);
const payrollData = allItems.filter(i => i.json.sheet === 'Payroll' || i.json.payroll_current !== undefined);
const subscriptionData = allItems.filter(i => i.json.sheet === 'Subscriptions' || i.json.subscription_revenue !== undefined);
const expensesData = allItems.filter(i => i.json.sheet === 'Expenses' || i.json.expense_amount !== undefined);

const totalRevenueCurrent = revenueData.reduce((sum, i) => sum + (parseFloat(i.json.revenue_current) || 0), 0);
const totalRevenuePrevious = revenueData.reduce((sum, i) => sum + (parseFloat(i.json.revenue_previous) || 0), 0);
const revenueChange = totalRevenuePrevious > 0 ? (((totalRevenueCurrent - totalRevenuePrevious) / totalRevenuePrevious) * 100).toFixed(1) : 0;

const totalPayrollCurrent = payrollData.reduce((sum, i) => sum + (parseFloat(i.json.payroll_current) || 0), 0);
const totalPayrollPrevious = payrollData.reduce((sum, i) => sum + (parseFloat(i.json.payroll_previous) || 0), 0);
const payrollChange = totalPayrollPrevious > 0 ? (((totalPayrollCurrent - totalPayrollPrevious) / totalPayrollPrevious) * 100).toFixed(1) : 0;

const totalMarketingSpend = expensesData.reduce((sum, i) => sum + (parseFloat(i.json.marketing_spend) || 0), 0);
const totalMarketingRevenue = revenueData.reduce((sum, i) => sum + (parseFloat(i.json.marketing_attributed_revenue) || 0), 0);
const marketingROI = totalMarketingSpend > 0 ? ((totalMarketingRevenue / totalMarketingSpend) * 100).toFixed(1) : 0;
const marketingROIPrevious = 85;
const marketingROIChange = (marketingROI - marketingROIPrevious).toFixed(1);

const currentCash = cashflowData.reduce((sum, i) => sum + (parseFloat(i.json.cash_balance) || 0), 0);
const monthlyBurnRate = expensesData.reduce((sum, i) => sum + (parseFloat(i.json.monthly_burn) || 0), 0);
const cashRunway = monthlyBurnRate > 0 ? (currentCash / monthlyBurnRate).toFixed(1) : 'N/A';

const totalSubscriptions = subscriptionData.reduce((sum, i) => sum + (parseFloat(i.json.subscription_revenue) || 0), 0);
const totalExpenses = expensesData.reduce((sum, i) => sum + (parseFloat(i.json.expense_amount) || 0), 0);

const today = new Date().toISOString().split('T')[0];

const revenueStatus = revenueChange < -10 ? '🔴 ALERT' : revenueChange < 0 ? '🟡 WARNING' : '🟢 GOOD';
const payrollStatus = payrollChange > 10 ? '🔴 ALERT' : payrollChange > 5 ? '🟡 WARNING' : '🟢 GOOD';
const cashRunwayStatus = parseFloat(cashRunway) < 3 ? '🔴 CRITICAL' : parseFloat(cashRunway) < 6 ? '🟡 WARNING' : '🟢 HEALTHY';
const marketingStatus = marketingROIChange > 0 ? '🟢 IMPROVING' : '🟡 DECLINING';

return [{
  json: {
    date: today,
    revenue_current: totalRevenueCurrent,
    revenue_previous: totalRevenuePrevious,
    revenue_change_pct: parseFloat(revenueChange),
    payroll_current: totalPayrollCurrent,
    payroll_change_pct: parseFloat(payrollChange),
    marketing_roi: parseFloat(marketingROI),
    marketing_roi_change: parseFloat(marketingROIChange),
    cash_balance: currentCash,
    monthly_burn_rate: monthlyBurnRate > 0 ? monthlyBurnRate / allItems.filter(i => i.json.monthly_burn).length : 0,
    cash_runway_months: parseFloat(cashRunway),
    subscriptions_mrr: totalSubscriptions,
    total_expenses: totalExpenses,
    revenue_status: revenueStatus,
    payroll_status: payrollStatus,
    cash_status: cashRunwayStatus,
    marketing_status: marketingStatus
  }
}];

const aiOutput = $('Generate AI Outreach Message1').item.json.output || '';
const financialData = $('Calculate KPIs & Status Labels').item.json;

return [{
  json: {
    ...financialData,
    telegram_report: aiOutput
  }
}];

